import{_ as e,o as s,c as r,a2 as i}from"./chunks/framework.Cuq8tsM6.js";const f=JSON.parse('{"title":"Spécifications Print","description":"","frontmatter":{"title":"Spécifications Print"},"headers":[],"relativePath":"docs/fr/advertisers/sponsored-mail/design-guide/print-specs.md","filePath":"docs/fr/advertisers/sponsored-mail/design-guide/print-specs.md"}'),l={name:"docs/fr/advertisers/sponsored-mail/design-guide/print-specs.md"};function n(o,t,a,d,g,p){return s(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="specifications-techniques" tabindex="-1">Spécifications Techniques <a class="header-anchor" href="#specifications-techniques" aria-label="Permalink to &quot;Spécifications Techniques&quot;">​</a></h1><p>Les contraintes impératives pour garantir une qualité d&#39;impression et de distribution optimale.</p><hr class="my-6"><h2 class="text-blue-200 mb-4">📐 Formats Papier (Flyers)</h2><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Format fini (Découpé)</th><th style="text-align:left;">Format fichier (Avec fond perdu)</th><th style="text-align:left;">Zone tranquille</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>A5</strong></td><td style="text-align:left;">148 x 210 mm</td><td style="text-align:left;"><strong>152 x 214 mm</strong></td><td style="text-align:left;">3 mm internes</td></tr><tr><td style="text-align:left;"><strong>A6</strong></td><td style="text-align:left;">105 x 148 mm</td><td style="text-align:left;"><strong>109 x 152 mm</strong></td><td style="text-align:left;">3 mm internes</td></tr><tr><td style="text-align:left;"><strong>Carte</strong></td><td style="text-align:left;">105 x 148 mm</td><td style="text-align:left;"><strong>109 x 152 mm</strong></td><td style="text-align:left;">Voir Gabarit</td></tr></tbody></table><br><div style="display:flex;gap:20px;flex-wrap:wrap;margin-bottom:40px;"><div style="flex:1;background:#fff5f5;border:1px solid #d73a49;padding:15px;border-radius:6px;"><strong class="text-red-200">Fond Perdu (Bleed) : 2mm</strong><br> La matière (image/fond) doit déborder de 2mm à l&#39;extérieur pour éviter les liserés blancs. </div><div style="flex:1;background:#f0fcf4;border:1px solid #28a745;padding:15px;border-radius:6px;"><strong class="text-green-200">Zone Tranquille : 3mm</strong><br> Aucun texte ni logo important ne doit se trouver à moins de 3mm du bord intérieur. </div></div><h2 class="text-purple-200 mb-4">🎁 Formats Échantillons (Sampling)</h2><p>getinside permet la distribution d&#39;échantillons seuls ou assemblés.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Taille</th><th style="text-align:left;">Poids Max</th><th style="text-align:left;">Développé Max (H + l + L)</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Format S</strong></td><td style="text-align:left;">Jusqu&#39;à <strong>15g</strong></td><td style="text-align:left;">Jusqu&#39;à <strong>15 cm</strong></td></tr><tr><td style="text-align:left;"><strong>Format M</strong></td><td style="text-align:left;">Jusqu&#39;à <strong>100g</strong></td><td style="text-align:left;">Jusqu&#39;à <strong>30 cm</strong></td></tr><tr><td style="text-align:left;"><strong>Format L</strong></td><td style="text-align:left;">Jusqu&#39;à <strong>450g</strong></td><td style="text-align:left;">Jusqu&#39;à <strong>40 cm</strong></td></tr></tbody></table><br><div style="margin-top:20px;border:1px solid #e1e4e8;border-radius:8px;overflow:hidden;"><div style="background:#f6f8fa;padding:15px;border-bottom:1px solid #e1e4e8;font-weight:bold;"> ✨ Service d&#39;Assemblage (Flyer + Échantillon) </div><div style="padding:24px;background:#fff;"><h3 class="mt-0 fs-4">Option &quot;Duo&quot; (Format S uniquement)</h3><p>Nous pouvons coller votre échantillon (taille S) sur un flyer A5 ou A6 pour maximiser l&#39;impact visuel.</p><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(250px, 1fr));gap:20px;margin-top:20px;"><div><strong>Technique :</strong><br> Utilisation d&#39;un point de <strong>colle fugitive</strong> (repositionnable) qui permet de détacher l&#39;échantillon sans abîmer le flyer. </div><div><strong>Engagement RSE :</strong><br> Cette prestation est réalisée par des <strong>Entreprises Adaptées (EA)</strong>. </div></div></div></div><h2 class="text-blue-200 mt-6 mb-4">🌐 Fichiers &amp; Couleurs</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(300px, 1fr));gap:20px;width:100%;"><div style="border:1px solid #e1e4e8;border-radius:8px;padding:20px;background:#fff;"><h3 class="mt-0 fs-4">📁 Type de fichier</h3><ul class="mb-0 pl-4"><li class="mb-2"><strong>PDF/X (Vectoriel) :</strong> À privilégier.</li><li><strong>JPG / PNG :</strong> 300 DPI minimum.</li></ul></div><div style="border:1px solid #e1e4e8;border-radius:8px;padding:20px;background:#fff;"><h3 class="mt-0 fs-4">🎨 Colorimétrie</h3><ul class="mb-0 pl-4"><li class="mb-2"><strong>Mode :</strong> CMJN obligatoire.</li><li class="mb-2"><strong>Profil :</strong> Coated FOGRA39.</li><li><strong>Taux d&#39;encrage :</strong> Max 300%.</li></ul></div></div>',14)])])}const u=e(l,[["render",n]]);export{f as __pageData,u as default};
